function xah_randomize_children_f(nodeX) {
  // nodeX can be any html element
  // randomize its children
  // http://xahlee.info/js/js_dom_randomize_list.html
  // version 2017-05-11

  const newNode = nodeX.cloneNode(true);
  const xChildren = newNode.children;
  const newNodeFrag = document.createDocumentFragment();

  while (xChildren.length > 0) {
    newNodeFrag.appendChild(
      xChildren[Math.floor(Math.random() * xChildren.length)],
    );
  }

  nodeX.innerHTML = "";
  nodeX.appendChild(newNodeFrag);
}

function initMarquee(selector, speed) {
  // Adjust speed
  const isFirefox = navigator.userAgent.toLowerCase().includes("firefox");
  if (!isFirefox) {
    speed = speed - 0.4;
  }

  const parentSelector = document.querySelector(selector);
  if (!parentSelector) return;
  const clone = parentSelector.innerHTML;
  let i = 0;
  parentSelector.insertAdjacentHTML("beforeend", clone);
  const firstElement = parentSelector.children[0];

  let scrollingAnimation = setInterval(function () {
    firstElement.style.marginLeft = `-${i}px`;

    if (i > firstElement.clientWidth) {
      i = 0;
    }
    i = i + speed;
  }, 0);

  parentSelector.addEventListener("mouseover", () => {
    clearInterval(scrollingAnimation);
  });

  parentSelector.addEventListener("mouseout", () => {
    scrollingAnimation = setInterval(function () {
      firstElement.style.marginLeft = `-${i}px`;

      if (i > firstElement.clientWidth) {
        i = 0;
      }
      i = i + speed;
    }, 0);
  });
}


